Script.Source:
import sailpoint.object.ProvisioningPlan;
import sailpoint.object.Identity;
import sailpoint.tools.Util;
import sailpoint.object.ProvisioningPlan.Operation;
import sailpoint.object.ProvisioningPlan.AttributeRequest;
import sailpoint.object.ProvisioningPlan.AccountRequest;
import sailpoint.object.ProvisioningPlan.AccountRequest.Operation;
import sailpoint.api.IdentityService;
import sailpoint.object.Application;
import sailpoint.object.Link;

Identity identityObj = null;
ProvisioningPlan plan = null;
Application adApp = null;
IdentityService idService = null;
String adNativeIdentity;

try{
idService = new IdentityService(context);
adApp = context.getObjectByName(Application.class, "ActiveDirectory");

if(Util.isNotNullOrEmpty(identityName)){
identityObj = context.getObjectByName(Identity.class ,identityName);
}
if (adApp != null) {
List links =  idService.getLinks(identityObj, adApp);
for(Link link : links){
String nativeIdentity = link.getNativeIdentity();
if(Util.isNotNullOrEmpty(nativeIdentity) && !nativeIdentity.contains("ADM")){
adNativeIdentity = nativeIdentity;
break;
}
}
}
plan = new ProvisioningPlan();
plan.setIdentity(identityObj);
AccountRequest accReq = new AccountRequest();
accReq.setNativeIdentity(adNativeIdentity);
accReq.setOperation(ProvisioningPlan.AccountRequest.Operation.Modify);
if("department".equalsIgnoreCase(event.getNewObject().getAttribute(trigger.getAttributeName()))){
accReq.add(new AttributeRequest("department" ,ProvisioningPlan.Operation.Set ,event.getNewObject().getAttribute(trigger.getAttributeName())));
}
plan.add(accReq);
}catch(Exception e){
log.error("Exception in buildPlan Step "+e.getMessage());
}finally{
context.decache(identityObj);
context.decache(adApp);
}

log.error(" Args from wfcontext in build paln step : "+wfcontext.getArguments().getMap());

log.error(" plan in buildpaln step : "+plan.toXml());
return plan;

import java.util.Calendar;
import sailpoint.api.IdentityService;
import sailpoint.object.Application;
import sailpoint.object.ApprovalItem;
import sailpoint.object.ApprovalSet;
import sailpoint.object.Attributes;
import sailpoint.object.Identity;
import sailpoint.object.ProvisioningPlan;
import sailpoint.object.WorkItem;
import sailpoint.tools.GeneralException;

ApprovalSet set = new ApprovalSet();
ApprovalItem approvalItem =new ApprovalItem();
approvalItem.setApplication("ActiveDirectory");
approvalItem.setNativeIdentity(provisioningPlan.getAccountRequests().get(0).getNativeIdentity());
approvalItem.setOperation("Set");
approvalItem.setValue("department", event.getNewObject().getAttribute(attribute));
set.add(approvalItem);
log.error(" Approval Set in Build Approval Set Step : "+set.toXml());

return set;

