import sailpoint.workflow.IdentityRequestLibrary;

if ( item == null ) 
return;

//log.error(" ApprovaSet in provision approval subprocess -approval step AfterScript.."+approvalSet.toXml());
assimilateWorkItemApprovalSet(wfcontext, item, approvalSet);          
